export class vec2 {
  private x: number;
  private y: number;

  public constructor(x: number = 0, y: number = 0) {
    this.x = x;
    this.y = y;
  }

  public get vx(): number {
    return this.x;
  }

  public set vx(point: number) {
    this.x = point;
  }

  public get vy(): number {
    return this.y;
  }

  public set vy(point: number) {
    this.y = point;
  }

  public static get zero(): vec2 {
    return new vec2();
  }

  public static get one(): vec2 {
    return new vec2(1, 1);
  }

  public copyFrom(v: vec2): void {
    this.x = v.x;
    this.y = v.y;
  }

  public setFromJson(json: any): void {
    if (json.x !== undefined) {
      this.x = Number(json.x);
    }

    if (json.y !== undefined) {
      this.y = Number(json.y);
    }
  }

  public toArray(): number[] {
    return [this.x, this.y];
  }

  public toFloat32(): Float32Array {
    return new Float32Array(this.toArray());
  }
}
